        debugPrint('Notification opened app: ${message.messageId}');
        _handleNotificationTap(message);
      });

      // Check if app was opened from a terminated state via notification
      RemoteMessage? initialMessage =
          await _firebaseMessaging.getInitialMessage();
      if (initialMessage != null) {
        _handleNotificationTap(initialMessage);
      }
    }
  }

  void _injectFCMToken() {
    if (_fcmToken != null) {
      _controller.runJavaScript('''
        if (window.onFCMTokenReceived) {
          window.onFCMTokenReceived('$_fcmToken');
        }
        window.fcmToken = '$_fcmToken';
      ''');
    }
  }

  void _handleForegroundNotification(RemoteMessage message) {
    final data = jsonEncode({
      'title': message.notification?.title ?? '',
      'body': message.notification?.body ?? '',
      'data': message.data,
    });

    _controller.runJavaScript('''
      if (window.onPushNotificationReceived) {
        window.onPushNotificationReceived($data);
      }
    ''');

    // Also show a native snackbar
    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            message.notification?.title ?? 'New notification',
