                _controller.loadRequest(Uri.parse(message.data['url']));
              }
            },
          ),
          duration: const Duration(seconds: 4),
        ),
      );
    }
  }

  void _handleNotificationTap(RemoteMessage message) {
    if (message.data.containsKey('url')) {
      _controller.loadRequest(Uri.parse(message.data['url']));
    }

    final data = jsonEncode({
      'title': message.notification?.title ?? '',
      'body': message.notification?.body ?? '',
      'data': message.data,
    });

    _controller.runJavaScript('''
      if (window.onPushNotificationTapped) {
        window.onPushNotificationTapped($data);
      }
    ''');
  }

  Future<void> _handleCameraRequest(String message) async {
    try {
      final Map<String, dynamic> request = jsonDecode(message);
      final String source = request['source'] ?? 'camera';
      final String callbackName = request['callback'] ?? 'onImageCaptured';
      final int quality = request['quality'] ?? 80;
      final double? maxWidth = request['maxWidth']?.toDouble();
      final double? maxHeight = request['maxHeight']?.toDouble();

      XFile? image;

      if (source == 'gallery') {
        image = await _imagePicker.pickImage(
          source: ImageSource.gallery,
          imageQuality: quality,
          maxWidth: maxWidth,
          maxHeight: maxHeight,
        );
      } else {
        image = await _imagePicker.pickImage(
          source: ImageSource.camera,
          imageQuality: quality,
          maxWidth: maxWidth,
          maxHeight: maxHeight,
          preferredCameraDevice:
              request['preferFront'] == true
                  ? CameraDevice.front
                  : CameraDevice.rear,
        );
      }

      if (image != null) {
        final bytes = await image.readAsBytes();
        final base64Image = base64Encode(bytes);
        final mimeType =
            image.path.endsWith('.png') ? 'image/png' : 'image/jpeg';

        _controller.runJavaScript('''
          if (window.$callbackName) {
            window.$callbackName({
              success: true,
